const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Food and drink","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une tasse de café fumante","image_prompt":"A steaming cup of coffee on a wooden table"},{"id":"B","text":"Un verre de jus d'orange frais","image_prompt":"A glass of fresh orange juice with pulp"},{"id":"C","text":"Une bouteille d'eau minérale","image_prompt":"A clear bottle of mineral water with ice"},{"id":"D","text":"Un bol de soupe chaude","image_prompt":"A bowl of hot soup with vegetables"}],"correct":1,"transcript_fr":"Chaque matin, je prends un grand verre de jus d'orange pressé pour bien commencer la journée.","transcript_en":"Every morning, I drink a big glass of freshly squeezed orange juice to start the day right.","points":[{"point":1,"male_lines":["Chaque matin, je prends un grand verre de jus d'orange pressé pour bien commencer la journée."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus rouge dans la rue","image_prompt":"A red city bus on a busy street"},{"id":"B","text":"Un train à grande vitesse","image_prompt":"A high-speed train at a modern station"},{"id":"C","text":"Un avion qui décolle","image_prompt":"An airplane taking off from a runway"},{"id":"D","text":"Un métro souterrain","image_prompt":"A subway train arriving at an underground station"}],"correct":3,"transcript_fr":"Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus.","transcript_en":"I always take the subway to go to work, it's faster than the bus.","points":[{"point":1,"male_lines":["Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un ciel bleu sans nuages","image_prompt":"A clear blue sky with bright sun"},{"id":"B","text":"De la neige qui tombe","image_prompt":"Heavy snowfall on a winter street"},{"id":"C","text":"Un orage avec éclairs","image_prompt":"A thunderstorm with lightning bolts"},{"id":"D","text":"De la pluie fine","image_prompt":"Light rain falling on an umbrella"}],"correct":2,"transcript_fr":"Attention, un violent orage est prévu pour cet après-midi avec des éclairs et du tonnerre.","transcript_en":"Warning, a violent thunderstorm is expected this afternoon with lightning and thunder.","points":[{"point":1,"male_lines":["Attention, un violent orage est prévu pour cet après-midi avec des éclairs et du tonnerre."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un panier d'épicerie plein","image_prompt":"A full grocery basket with vegetables and fruits"},{"id":"B","text":"Un caddie de supermarché","image_prompt":"A shopping cart in a supermarket aisle"},{"id":"C","text":"Un sac de vêtements","image_prompt":"A shopping bag with clothes sticking out"},{"id":"D","text":"Une carte de crédit","image_prompt":"A credit card being swiped at a terminal"}],"correct":0,"transcript_fr":"Il faut que j'aille remplir mon panier d'épicerie, le réfrigérateur est presque vide.","transcript_en":"I need to go fill my grocery basket, the refrigerator is almost empty.","points":[{"point":1,"male_lines":["Il faut que j'aille remplir mon panier d'épicerie, le réfrigérateur est presque vide."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un ordinateur portable ouvert","image_prompt":"An open laptop on a desk with documents"},{"id":"B","text":"Une imprimante qui fonctionne","image_prompt":"A printer printing papers in an office"},{"id":"C","text":"Un téléphone fixe sur un bureau","image_prompt":"A landline phone on an office desk"},{"id":"D","text":"Une pile de documents","image_prompt":"A stack of papers and folders on a desk"}],"correct":1,"transcript_fr":"L'imprimante fait un bruit étrange, je pense qu'il faut changer le toner bientôt.","transcript_en":"The printer is making a strange noise, I think we need to change the toner soon.","points":[{"point":1,"male_lines":["L'imprimante fait un bruit étrange, je pense qu'il faut changer le toner bientôt."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Restaurant","question":"Où se déroule cette conversation ?","options":[{"id":"A","text":"Dans une bibliothèque","image_prompt":""},{"id":"B","text":"Dans un restaurant","image_prompt":""},{"id":"C","text":"Dans un magasin de vêtements","image_prompt":""},{"id":"D","text":"Dans une pharmacie","image_prompt":""}],"correct":1,"transcript_fr":"Bonjour Madame, avez-vous réservé une table ? Oui, au nom de Martin, pour quatre personnes. Très bien, suivez-moi par ici. Voici la carte, votre serveur arrivera dans quelques minutes.","transcript_en":"Hello Madam, do you have a reservation? Yes, under the name Martin, for four people. Very well, follow me this way. Here is the menu, your server will be with you in a few minutes.","points":[{"point":1,"male_lines":["Bonjour Madame, avez-vous réservé une table ?","Très bien, suivez-moi par ici."],"female_lines":["Oui, au nom de Martin, pour quatre personnes.","Voici la carte, votre serveur arrivera dans quelques minutes."]},{"point":2,"male_lines":["Merci beaucoup.","Pouvez-vous nous apporter de l'eau en attendant ?"],"female_lines":["Avec plaisir.","Bien sûr, tout de suite."]}]},{"id":8,"section":"B","theme":"Bank","question":"Quel est le sujet principal de cette conversation ?","options":[{"id":"A","text":"Ouvrir un compte bancaire","image_prompt":""},{"id":"B","text":"Demander un prêt hypothécaire","image_prompt":""},{"id":"C","text":"Faire un virement international","image_prompt":""},{"id":"D","text":"Renouveler une carte de crédit","image_prompt":""}],"correct":0,"transcript_fr":"Bonjour, je voudrais ouvrir un compte chèques s'il vous plaît. Bien sûr Monsieur, avez-vous une pièce d'identité avec photo ? Oui, voici mon permis de conduire. Parfait, remplissez ce formulaire et je préparerai votre dossier.","transcript_en":"Hello, I would like to open a checking account please. Of course Sir, do you have a photo ID? Yes, here is my driver's license. Perfect, fill out this form and I will prepare your file.","points":[{"point":1,"male_lines":["Bonjour, je voudrais ouvrir un compte chèques s'il vous plaît.","Oui, voici mon permis de conduire."],"female_lines":["Bien sûr Monsieur, avez-vous une pièce d'identité avec photo ?","Parfait, remplissez ce formulaire et je préparerai votre dossier."]},{"point":2,"male_lines":["Combien de temps cela prend-il ?","Merci pour votre aide."],"female_lines":["Environ quinze minutes.","Je vous en prie, c'est mon travail."]}]},{"id":9,"section":"B","theme":"Doctor","question":"Quel problème de santé est mentionné ?","options":[{"id":"A","text":"Une fracture","image_prompt":""},{"id":"B","text":"Une allergie","image_prompt":""},{"id":"C","text":"Un mal de tête","image_prompt":""},{"id":"D","text":"Une toux persistante","image_prompt":""}],"correct":3,"transcript_fr":"Docteur, je tousse depuis trois semaines et ça ne passe pas. Avez-vous de la fièvre ? Non, mais j'ai mal à la gorge le matin. Je vais vous ausculter, ouvrez la bouche et dites 'aaaah'.","transcript_en":"Doctor, I have been coughing for three weeks and it won't go away. Do you have a fever? No, but my throat hurts in the morning. I will examine you, open your mouth and say 'aaaah'.","points":[{"point":1,"male_lines":["Docteur, je tousse depuis trois semaines et ça ne passe pas.","Non, mais j'ai mal à la gorge le matin."],"female_lines":["Avez-vous de la fièvre ?","Je vais vous ausculter, ouvrez la bouche et dites 'aaaah'."]},{"point":2,"male_lines":["Est-ce grave docteur ?","Quand dois-je revenir ?"],"female_lines":["C'est une bronchite, rien de sérieux.","Dans une semaine si ça ne va pas mieux."]}]},{"id":10,"section":"B","theme":"Post office","question":"Quel service le client demande-t-il ?","options":[{"id":"A","text":"Acheter des timbres","image_prompt":""},{"id":"B","text":"Envoyer un colis","image_prompt":""},{"id":"C","text":"Retirer de l'argent","image_prompt":""},{"id":"D","text":"Renouveler un passeport","image_prompt":""}],"correct":1,"transcript_fr":"Bonjour, je voudrais envoyer ce colis au Canada. Quel est le poids ? Environ deux kilos. Voulez-vous l'envoi standard ou express ? L'express s'il vous plaît, c'est urgent.","transcript_en":"Hello, I would like to send this package to Canada. What is the weight? About two kilos. Do you want standard or express shipping? Express please, it's urgent.","points":[{"point":1,"male_lines":["Bonjour, je voudrais envoyer ce colis au Canada.","Environ deux kilos."],"female_lines":["Quel est le poids ?","Voulez-vous l'envoi standard ou express ?"]},{"point":2,"male_lines":["L'express s'il vous plaît, c'est urgent.","Combien ça coûte ?"],"female_lines":["Très bien, remplissez cette déclaration.","Vingt-cinq euros avec l'assurance."]}]},{"id":11,"section":"C","theme":"Airport announcement","question":"Quelle information est donnée dans cette annonce ?","options":[{"id":"A","text":"Un vol est annulé","image_prompt":""},{"id":"B","text":"Un vol est retardé","image_prompt":""},{"id":"C","text":"L'embarquement commence","image_prompt":""},{"id":"D","text":"La porte d'embarquement a changé","image_prompt":""}],"correct":2,"transcript_fr":"Mesdames et Messieurs, nous vous informons que l'embarquement pour le vol AC875 à destination de Montréal va commencer. Les passagers des rangées 25 à 35 sont priés de se présenter à la porte 42. Merci de préparer votre carte d'embarquement et votre passeport.","transcript_en":"Ladies and Gentlemen, we inform you that boarding for flight AC875 to Montreal is about to begin. Passengers from rows 25 to 35 are requested to proceed to gate 42. Please have your boarding pass and passport ready.","points":[{"point":1,"male_lines":["Mesdames et Messieurs, nous vous informons que l'embarquement pour le vol AC875 à destination de Montréal va commencer."],"female_lines":[]},{"point":2,"male_lines":["Les passagers des rangées 25 à 35 sont priés de se présenter à la porte 42."],"female_lines":[]},{"point":3,"male_lines":["Merci de préparer votre carte d'embarquement et votre passeport."],"female_lines":[]},{"point":4,"male_lines":["Nous vous remercions de votre attention."],"female_lines":[]},{"point":5,"male_lines":["Bonne continuation avec Air Canada."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Quelle promotion est annoncée ?","options":[{"id":"A","text":"50% sur les fruits","image_prompt":""},{"id":"B","text":"Deux pour le prix d'un","image_prompt":""},{"id":"C","text":"Carte de fidélité double points","image_prompt":""},{"id":"D","text":"Produits bio à -30%","image_prompt":""}],"correct":1,"transcript_fr":"Chers clients, profitez de notre offre spéciale aujourd'hui uniquement. Tous les produits laitiers sont en promotion deux pour le prix d'un. Rendez-vous au rayon frais dès maintenant. Cette offre est valable jusqu'à la fermeture du magasin ce soir.","transcript_en":"Dear customers, take advantage of our special offer today only. All dairy products are on promotion buy one get one free. Go to the fresh section right now. This offer is valid until the store closes tonight.","points":[{"point":1,"male_lines":["Chers clients, profitez de notre offre spéciale aujourd'hui uniquement."],"female_lines":[]},{"point":2,"male_lines":["Tous les produits laitiers sont en promotion deux pour le prix d'un."],"female_lines":[]},{"point":3,"male_lines":["Rendez-vous au rayon frais dès maintenant."],"female_lines":[]},{"point":4,"male_lines":["Cette offre est valable jusqu'à la fermeture du magasin ce soir."],"female_lines":[]},{"point":5,"male_lines":["Merci de votre fidélité."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Museum announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"Fermeture temporaire","image_prompt":""},{"id":"B","text":"Nouvelle exposition","image_prompt":""},{"id":"C","text":"Visite guidée gratuite","image_prompt":""},{"id":"D","text":"Modification des horaires","image_prompt":""}],"correct":3,"transcript_fr":"Attention visiteurs, le musée fermera exceptionnellement à 17 heures aujourd'hui au lieu de 19 heures. Nous vous prions de bien vouloir terminer votre visite dans les temps. Les caisses fermeront à 16h30. Merci de votre compréhension.","transcript_en":"Attention visitors, the museum will exceptionally close at 5 PM today instead of 7 PM. We kindly ask you to finish your visit on time. The ticket office will close at 4:30 PM. Thank you for your understanding.","points":[{"point":1,"male_lines":["Attention visiteurs, le musée fermera exceptionnellement à 17 heures aujourd'hui au lieu de 19 heures."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de bien vouloir terminer votre visite dans les temps."],"female_lines":[]},{"point":3,"male_lines":["Les caisses fermeront à 16h30."],"female_lines":[]},{"point":4,"male_lines":["Merci de votre compréhension."],"female_lines":[]},{"point":5,"male_lines":["Bonne visite à tous."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Weather alert","question":"Quel type d'alerte est diffusée ?","options":[{"id":"A","text":"Alerte neige et verglas","image_prompt":""},{"id":"B","text":"Alerte canicule","image_prompt":""},{"id":"C","text":"Alerte inondation","image_prompt":""},{"id":"D","text":"Alerte vents violents","image_prompt":""}],"correct":0,"transcript_fr":"Météo Canada émet un avertissement de neige abondante pour la région de Montréal. Accumulation prévue de 25 à 30 centimètres d'ici demain matin. Les conditions routières seront difficiles. Évitez les déplacements non essentiels.","transcript_en":"Environment Canada is issuing a heavy snowfall warning for the Montreal region. Accumulation of 25 to 30 centimeters expected by tomorrow morning. Road conditions will be difficult. Avoid non-essential travel.","points":[{"point":1,"male_lines":["Météo Canada émet un avertissement de neige abondante pour la région de Montréal."],"female_lines":[]},{"point":2,"male_lines":["Accumulation prévue de 25 à 30 centimètres d'ici demain matin."],"female_lines":[]},{"point":3,"male_lines":["Les conditions routières seront difficiles."],"female_lines":[]},{"point":4,"male_lines":["Évitez les déplacements non essentiels."],"female_lines":[]},{"point":5,"male_lines":["Restez à l'abri et en sécurité."],"female_lines":[]}]},{"id":15,"section":"C","theme":"University announcement","question":"Quelle information concernant les examens est donnée ?","options":[{"id":"A","text":"Les examens sont reportés","image_prompt":""},{"id":"B","text":"La salle d'examen a changé","image_prompt":""},{"id":"C","text":"Les résultats sont disponibles","image_prompt":""},{"id":"D","text":"Inscription aux examens obligatoire","image_prompt":""}],"correct":1,"transcript_fr":"Étudiants inscrits au cours de français avancé, veuillez noter que l'examen final aura lieu en salle B204 et non en amphithéâtre A comme prévu. L'horaire reste inchangé : 9 heures demain matin. Apportez votre carte étudiante.","transcript_en":"Students enrolled in advanced French, please note that the final exam will take place in room B204 and not in lecture hall A as planned. The schedule remains unchanged: 9 AM tomorrow morning. Bring your student ID.","points":[{"point":1,"male_lines":["Étudiants inscrits au cours de français avancé, veuillez noter que l'examen final aura lieu en salle B204 et non en amphithéâtre A comme prévu."],"female_lines":[]},{"point":2,"male_lines":["L'horaire reste inchangé : 9 heures demain matin."],"female_lines":[]},{"point":3,"male_lines":["Apportez votre carte étudiante."],"female_lines":[]},{"point":4,"male_lines":["Aucun retard ne sera accepté."],"female_lines":[]},{"point":5,"male_lines":["Bonne chance à tous."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Train station","question":"Quel problème est signalé ?","options":[{"id":"A","text":"Grève des contrôleurs","image_prompt":""},{"id":"B","text":"Panne technique","image_prompt":""},{"id":"C","text":"Retard dû aux intempéries","image_prompt":""},{"id":"D","text":"Travaux sur la voie","image_prompt":""}],"correct":2,"transcript_fr":"Voyageurs du train 684 en direction de Québec, nous regrettons de vous informer que votre train aura quarante minutes de retard en raison d'un glissement de terrain causé par les fortes pluies. Nous vous prions de nous excuser pour ce désagrément.","transcript_en":"Passengers of train 684 to Quebec, we regret to inform you that your train will be forty minutes late due to a landslide caused by heavy rain. We apologize for this inconvenience.","points":[{"point":1,"male_lines":["Voyageurs du train 684 en direction de Québec, nous regrettons de vous informer que votre train aura quarante minutes de retard en raison d'un glissement de terrain causé par les fortes pluies."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de nous excuser pour ce désagrément."],"female_lines":[]},{"point":3,"male_lines":["Un service de navette est mis en place."],"female_lines":[]},{"point":4,"male_lines":["Rendez-vous au quai 5 pour plus d'informations."],"female_lines":[]},{"point":5,"male_lines":["Merci de votre patience."],"female_lines":[]}]},{"id":17,"section":"D","theme":"Job interview","question":"Quelle est l'intention du candidat ?","options":[{"id":"A","text":"Négocier son salaire","image_prompt":""},{"id":"B","text":"Demander une formation","image_prompt":""},{"id":"C","text":"Obtenir des informations sur le poste","image_prompt":""},{"id":"D","text":"Proposer une date de début","image_prompt":""}],"correct":2,"transcript_fr":"Pouvez-vous me décrire un peu plus les responsabilités de ce poste ? Bien sûr, vous seriez responsable de l'accueil des clients et de la gestion des appels. Et les horaires sont flexibles ? Oui, nous proposons le télétravail deux jours par semaine.","transcript_en":"Can you describe the responsibilities of this position a bit more? Of course, you would be responsible for client reception and call management. And are the hours flexible? Yes, we offer remote work two days a week.","points":[{"point":1,"male_lines":["Pouvez-vous me décrire un peu plus les responsabilités de ce poste ?","Et les horaires sont flexibles ?"],"female_lines":["Bien sûr, vous seriez responsable de l'accueil des clients et de la gestion des appels.","Oui, nous proposons le télétravail deux jours par semaine."]},{"point":2,"male_lines":["Cela me convient parfaitement.","Quand puis-je commencer ?"],"female_lines":["Nous avons besoin de quelqu'un rapidement.","La semaine prochaine si possible."]},{"point":3,"male_lines":["Parfait, je suis disponible.","Merci pour cette opportunité."],"female_lines":["Nous vous contacterons demain.","Avez-vous d'autres questions ?"]},{"point":4,"male_lines":["Non, c'est très clair.","Au revoir et merci."],"female_lines":["Au revoir Monsieur.","Bonne journée à vous."]}]},{"id":18,"section":"D","theme":"Complaint","question":"Que veut obtenir le client ?","options":[{"id":"A","text":"Un remboursement total","image_prompt":""},{"id":"B","text":"Un échange gratuit","image_prompt":""},{"id":"C","text":"Une réparation","image_prompt":""},{"id":"D","text":"Un avoir","image_prompt":""}],"correct":0,"transcript_fr":"Ce téléphone ne fonctionne plus après une semaine, je veux être remboursé. Je comprends votre mécontentement, mais avez-vous la garantie ? Oui, bien sûr, voici le reçu. Très bien, je vais procéder au remboursement sur votre carte.","transcript_en":"This phone stopped working after one week, I want a refund. I understand your dissatisfaction, but do you have the warranty? Yes, of course, here is the receipt. Very well, I will process the refund to your card.","points":[{"point":1,"male_lines":["Ce téléphone ne fonctionne plus après une semaine, je veux être remboursé.","Oui, bien sûr, voici le reçu."],"female_lines":["Je comprends votre mécontentement, mais avez-vous la garantie ?","Très bien, je vais procéder au remboursement sur votre carte."]},{"point":2,"male_lines":["Combien de temps cela prend ?","Parfait."],"female_lines":["Trois à cinq jours ouvrés.","Voulez-vous un autre modèle ?"]},{"point":3,"male_lines":["Non, je préfère l'argent.","Merci beaucoup."],"female_lines":["Comme vous voulez.","Je vous en prie."]},{"point":4,"male_lines":["Bonne journée.","Au revoir."],"female_lines":["À bientôt.","Au revoir Monsieur."]}]},{"id":19,"section":"D","theme":"Invitation","question":"Quelle est la réaction de la femme ?","options":[{"id":"A","text":"Elle accepte avec enthousiasme","image_prompt":""},{"id":"B","text":"Elle refuse poliment","image_prompt":""},{"id":"C","text":"Elle demande plus de détails","image_prompt":""},{"id":"D","text":"Elle hésite et demande du temps","image_prompt":""}],"correct":1,"transcript_fr":"Je voudrais vous inviter à dîner samedi soir. C'est gentil, mais je suis déjà occupée ce soir-là. Peut-être une autre fois ? Oui, pourquoi pas, appelez-moi la semaine prochaine.","transcript_en":"I would like to invite you to dinner Saturday evening. That's kind, but I am already busy that evening. Maybe another time? Yes, why not, call me next week.","points":[{"point":1,"male_lines":["Je voudrais vous inviter à dîner samedi soir.","Peut-être une autre fois ?"],"female_lines":["C'est gentil, mais je suis déjà occupée ce soir-là.","Oui, pourquoi pas, appelez-moi la semaine prochaine."]},{"point":2,"male_lines":["Je comprends, pas de problème.","À la semaine prochaine alors."],"female_lines":["Désolée vraiment.","Oui, on verra ça."]},{"point":3,"male_lines":["Passez une bonne soirée.","Merci quand même."],"female_lines":["Merci, vous aussi.","De rien."]},{"point":4,"male_lines":["Au revoir.","À bientôt."],"female_lines":["Au revoir.","Salut."]}]},{"id":20,"section":"D","theme":"Request","question":"Que demande l'homme ?","options":[{"id":"A","text":"De l'aide pour un déménagement","image_prompt":""},{"id":"B","text":"Un prêt d'argent","image_prompt":""},{"id":"C","text":"Un conseil professionnel","image_prompt":""},{"id":"D","text":"Un service de transport","image_prompt":""}],"correct":0,"transcript_fr":"Tu pourrais m'aider à déménager samedi ? J'ai beaucoup de cartons. Bien sûr, à quelle heure ? Vers 9 heures du matin. Parfait, je serai là avec ma camionnette.","transcript_en":"Could you help me move Saturday? I have a lot of boxes. Of course, what time? Around 9 in the morning. Perfect, I'll be there with my van.","points":[{"point":1,"male_lines":["Tu pourrais m'aider à déménager samedi ? J'ai beaucoup de cartons.","Vers 9 heures du matin."],"female_lines":["Bien sûr, à quelle heure ?","Parfait, je serai là avec ma camionnette."]},{"point":2,"male_lines":["Super, merci beaucoup.","On se retrouve chez moi ?"],"female_lines":["Avec plaisir.","Oui, donne-moi ton adresse."]},{"point":3,"male_lines":["C'est le 123 rue Principale.","À samedi alors."],"female_lines":["J'ai noté.","À samedi, n'oublie pas le café."]},{"point":4,"male_lines":["Promis, je préparerai tout.","Salut."],"female_lines":["Génial.","Bye."]}]},{"id":21,"section":"D","theme":"Advice","question":"Quel conseil donne la femme ?","options":[{"id":"A","text":"Changer de médecin","image_prompt":""},{"id":"B","text":"Prendre des vacances","image_prompt":""},{"id":"C","text":"Faire du sport","image_prompt":""},{"id":"D","text":"Consulter un spécialiste","image_prompt":""}],"correct":3,"transcript_fr":"Mon dos me fait toujours mal, que faire ? Tu devrais consulter un ostéopathe, ça m'a beaucoup aidé. Tu connais un bon praticien ? Oui, je te donne son numéro, il est très compétent.","transcript_en":"My back still hurts, what should I do? You should see an osteopath, it helped me a lot. Do you know a good practitioner? Yes, I'll give you his number, he is very competent.","points":[{"point":1,"male_lines":["Mon dos me fait toujours mal, que faire ?","Tu connais un bon praticien ?"],"female_lines":["Tu devrais consulter un ostéopathe, ça m'a beaucoup aidé.","Oui, je te donne son numéro, il est très compétent."]},{"point":2,"male_lines":["Merci, j'appellerai demain.","C'est cher ?"],"female_lines":["Fais-le vite.","Environ soixante euros la séance."]},{"point":3,"male_lines":["D'accord, je verrai.","Tu as été combien de fois ?"],"female_lines":["Ça vaut le coup.","Trois séances ont suffi."]},{"point":4,"male_lines":["Parfait, j'espère que ça marchera.","Merci pour le conseil."],"female_lines":["Je croise les doigts.","De rien, tiens-moi au courant."]}]},{"id":22,"section":"D","theme":"Suggestion","question":"Quelle suggestion fait l'homme ?","options":[{"id":"A","text":"Aller au cinéma","image_prompt":""},{"id":"B","text":"Faire une randonnée","image_prompt":""},{"id":"C","text":"Visiter un musée","image_prompt":""},{"id":"D","text":"Dîner au restaurant","image_prompt":""}],"correct":1,"transcript_fr":"Et si on faisait une randonnée ce week-end ? Il fait beau. Bonne idée, où veux-tu aller ? Au parc national de la Jacques-Cartier, les sentiers sont magnifiques. D'accord, préparons un pique-nique.","transcript_en":"What if we went hiking this weekend? The weather is nice. Good idea, where do you want to go? To Jacques-Cartier National Park, the trails are magnificent. Okay, let's prepare a picnic.","points":[{"point":1,"male_lines":["Et si on faisait une randonnée ce week-end ? Il fait beau.","Au parc national de la Jacques-Cartier, les sentiers sont magnifiques."],"female_lines":["Bonne idée, où veux-tu aller ?","D'accord, préparons un pique-nique."]},{"point":2,"male_lines":["Je connais un beau spot.","On part à quelle heure ?"],"female_lines":["Montre-moi sur la carte.","Vers 8 heures pour éviter la foule."]},{"point":3,"male_lines":["Parfait, je préparerai les sandwiches.","N'oublie pas l'eau."],"female_lines":["Je m'occupe des fruits.","Et de la crème solaire."]},{"point":4,"male_lines":["Bonne idée.","À samedi alors."],"female_lines":["Hâte d'y être.","À samedi."]}]},{"id":23,"section":"E","theme":"Environmental interview","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"La déforestation","image_prompt":""},{"id":"B","text":"Le réchauffement climatique","image_prompt":""},{"id":"C","text":"La pollution plastique","image_prompt":""},{"id":"D","text":"La biodiversité","image_prompt":""}],"correct":2,"transcript_fr":"Docteur Tremblay, votre étude sur les océans inquiète beaucoup. Oui, nous avons trouvé du plastique microscopique dans 90% des poissons analysés. C'est alarmant, quelles sont vos recommandations ? Il faut bannir les sacs plastiques à usage unique immédiatement.","transcript_en":"Doctor Tremblay, your study on the oceans is very worrying. Yes, we found microscopic plastic in 90% of the fish analyzed. This is alarming, what are your recommendations? We must ban single-use plastic bags immediately.","points":[{"point":1,"male_lines":["Docteur Tremblay, votre étude sur les océans inquiète beaucoup.","C'est alarmant, quelles sont vos recommandations ?"],"female_lines":["Oui, nous avons trouvé du plastique microscopique dans 90% des poissons analysés.","Il faut bannir les sacs plastiques à usage unique immédiatement."]},{"point":2,"male_lines":["Les gouvernements sont-ils réceptifs ?","Quel délai envisagez-vous ?"],"female_lines":["Certains progressent, d'autres traînent les pieds.","Cinq ans maximum pour une vraie différence."]},{"point":3,"male_lines":["Et les industriels ?","Ils ont peur des coûts ?"],"female_lines":["Ils résistent mais les alternatives existent.","Oui, mais à long terme c'est rentable."]},{"point":4,"male_lines":["Que peut faire le citoyen ?","Merci pour ces informations."],"female_lines":["Refuser le plastique au quotidien.","Merci de m'avoir reçue."]}]},{"id":24,"section":"E","theme":"Economic interview","question":"Quel secteur économique est discuté ?","options":[{"id":"A","text":"L'immobilier","image_prompt":""},{"id":"B","text":"Les technologies","image_prompt":""},{"id":"C","text":"L'agriculture","image_prompt":""},{"id":"D","text":"Le tourisme","image_prompt":""}],"correct":0,"transcript_fr":"Monsieur Lefebvre, le marché immobilier s'emballe à Montréal. Oui, les prix ont augmenté de 15% cette année. Quelles sont les causes selon vous ? La pénurie de logements et les taux d'intérêt bas attirent les investisseurs.","transcript_en":"Mr. Lefebvre, the real estate market is booming in Montreal. Yes, prices have increased by 15% this year. What are the causes according to you? The housing shortage and low interest rates attract investors.","points":[{"point":1,"male_lines":["Monsieur Lefebvre, le marché immobilier s'emballe à Montréal.","Quelles sont les causes selon vous ?"],"female_lines":["Oui, les prix ont augmenté de 15% cette année.","La pénurie de logements et les taux d'intérêt bas attirent les investisseurs."]},{"point":2,"male_lines":["Est-ce une bulle ?","Que conseillez-vous aux acheteurs ?"],"female_lines":["Pas encore, mais attention.","Acheter maintenant avant que ça grimpe encore."]},{"point":3,"male_lines":["Et les locataires ?","Le gouvernement intervient ?"],"female_lines":["Ils sont en difficulté avec les loyers.","Des mesures sont prévues mais insuffisantes."]},{"point":4,"male_lines":["Quelle prévision pour 2025 ?","Merci pour votre analyse."],"female_lines":["Stabilisation probable à la fin de l'année.","Je vous en prie."]}]},{"id":25,"section":"E","theme":"Health interview","question":"Quelle maladie est au centre de la discussion ?","options":[{"id":"A","text":"Le diabète","image_prompt":""},{"id":"B","text":"Les maladies cardiaques","image_prompt":""},{"id":"C","text":"La dépression","image_prompt":""},{"id":"D","text":"Le cancer","image_prompt":""}],"correct":1,"transcript_fr":"Docteur Gagnon, les maladies cardiaques touchent de plus en plus de jeunes. Exactement, le stress et la sédentarité sont les coupables. Quels signes d'alerte faut-il surveiller ? Douleur thoracique, essoufflement, fatigue anormale.","transcript_en":"Doctor Gagnon, heart disease affects more and more young people. Exactly, stress and sedentary lifestyle are the culprits. What warning signs should we watch for? Chest pain, shortness of breath, abnormal fatigue.","points":[{"point":1,"male_lines":["Docteur Gagnon, les maladies cardiaques touchent de plus en plus de jeunes.","Quels signes d'alerte faut-il surveiller ?"],"female_lines":["Exactement, le stress et la sédentarité sont les coupables.","Douleur thoracique, essoufflement, fatigue anormale."]},{"point":2,"male_lines":["Comment prévenir ?","Le sport suffit ?"],"female_lines":["Alimentation équilibrée et exercice régulier.","C'est essentiel mais pas suffisant seul."]},{"point":3,"male_lines":["Les examens de dépistage ?","À quel âge commencer ?"],"female_lines":["À partir de quarante ans recommandé.","Plus tôt si antécédents familiaux."]},{"point":4,"male_lines":["Message final ?","Merci docteur."],"female_lines":["Écoutez votre corps.","De rien, prenez soin de vous."]}]},{"id":26,"section":"E","theme":"Cultural interview","question":"Quel événement culturel est présenté ?","options":[{"id":"A","text":"Un festival de musique","image_prompt":""},{"id":"B","text":"Une exposition d'art","image_prompt":""},{"id":"C","text":"Un festival de cinéma","image_prompt":""},{"id":"D","text":"Un salon du livre","image_prompt":""}],"correct":2,"transcript_fr":"Madame Dubois, le festival de cinéma de Québec bat son plein. Oui, nous avons cent vingt films cette année. Quelle est la programmation phare ? Notre rétrospective Hitchcock fait salle comble chaque soir.","transcript_en":"Mrs. Dubois, the Quebec City Film Festival is in full swing. Yes, we have one hundred twenty films this year. What is the flagship program? Our Hitchcock retrospective is sold out every evening.","points":[{"point":1,"male_lines":["Madame Dubois, le festival de cinéma de Québec bat son plein.","Quelle est la programmation phare ?"],"female_lines":["Oui, nous avons cent vingt films cette année.","Notre rétrospective Hitchcock fait salle comble chaque soir."]},{"point":2,"male_lines":["Des nouveautés aussi ?","Les billets sont encore disponibles ?"],"female_lines":["Beaucoup de premières canadiennes.","Pour certains films seulement."]},{"point":3,"male_lines":["Où se déroule le festival ?","Jusqu'à quand ?"],"female_lines":["Dans trois salles du centre-ville.","Jusqu'à dimanche prochain."]},{"point":4,"male_lines":["Je vais réserver.","Merci pour l'information."],"female_lines":["Faites vite, ça part vite.","Avec plaisir, bon festival."]}]},{"id":27,"section":"F","theme":"Urban planning debate","question":"Quel est le point de désaccord principal ?","options":[{"id":"A","text":"Le coût du projet","image_prompt":""},{"id":"B","text":"L'emplacement du parc","image_prompt":""},{"id":"C","text":"Le nombre d'arbres à couper","image_prompt":""},{"id":"D","text":"L'accès aux personnes handicapées","image_prompt":""}],"correct":2,"transcript_fr":"Ce nouveau projet va détruire cinquante arbres matures. C'est nécessaire pour la bibliothèque moderne. On pourrait adapter le design pour les sauver. Impossible, les fondations nécessitent cet espace précis.","transcript_en":"This new project will destroy fifty mature trees. It is necessary for the modern library. We could adapt the design to save them. Impossible, the foundations require this specific space.","points":[{"point":1,"male_lines":["Ce nouveau projet va détruire cinquante arbres matures.","On pourrait adapter le design pour les sauver."],"female_lines":["C'est nécessaire pour la bibliothèque moderne.","Impossible, les fondations nécessitent cet espace précis."]},{"point":2,"male_lines":["L'environnement est plus important.","Les citoyens protestent."],"female_lines":["L'éducation l'est aussi.","Une minorité bruyante seulement."]},{"point":3,"male_lines":["Faisons un référendum.","La mairie écoutera ?"],"female_lines":["Perdons pas de temps.","Ils ont déjà approuvé."]},{"point":4,"male_lines":["C'est une erreur.","On verra dans dix ans."],"female_lines":["Vous exagérez.","L'histoire me donnera raison."]}]},{"id":28,"section":"F","theme":"Education debate","question":"Quelle solution est proposée pour améliorer l'éducation ?","options":[{"id":"A","text":"Augmenter les salaires des enseignants","image_prompt":""},{"id":"B","text":"Réduire le nombre d'élèves par classe","image_prompt":""},{"id":"C","text":"Introduire plus de technologie","image_prompt":""},{"id":"D","text":"Augmenter les heures de cours","image_prompt":""}],"correct":1,"transcript_fr":"Les classes de trente élèves sont ingérables. Réduisons à vingt maximum. Ça coûte trop cher embaucher autant de profs. Investissons dans l'avenir, c'est prioritaire.","transcript_en":"Classes of thirty students are unmanageable. Let's reduce to twenty maximum. It costs too much to hire that many teachers. Let's invest in the future, it's a priority.","points":[{"point":1,"male_lines":["Les classes de trente élèves sont ingérables.","Investissons dans l'avenir, c'est prioritaire."],"female_lines":["Réduisons à vingt maximum.","Ça coûte trop cher embaucher autant de profs."]},{"point":2,"male_lines":["La qualité vaut le coût.","Où trouver l'argent ?"],"female_lines":["Pas sûr que ce soit la seule solution.","Augmentons les impôts locaux."]},{"point":3,"male_lines":["Les parents payeront plus ?","Inacceptable."],"female_lines":["La communauté doit contribuer.","C'est injuste pour les moins riches."]},{"point":4,"male_lines":["Trouvons un compromis.","Vingt-cinq élèves ?"],"female_lines":["Peut-être.","Acceptable temporairement."]}]},{"id":29,"section":"F","theme":"Work-life balance debate","question":"Quel argument défend la semaine de quatre jours ?","options":[{"id":"A","text":"Réduction des coûts de transport","image_prompt":""},{"id":"B","text":"Amélioration de la productivité","image_prompt":""},{"id":"C","text":"Moins de congés maladie","image_prompt":""},{"id":"D","text":"Meilleure rétention des employés","image_prompt":""}],"correct":1,"transcript_fr":"La semaine de quatre jours augmente la productivité. Pas convaincu, les délais souffriront. Les études montrent le contraire, les employés sont plus efficaces. Peut-être dans certains secteurs seulement.","transcript_en":"The four-day week increases productivity. Not convinced, deadlines will suffer. Studies show the opposite, employees are more efficient. Maybe in certain sectors only.","points":[{"point":1,"male_lines":["La semaine de quatre jours augmente la productivité.","Les études montrent le contraire, les employés sont plus efficaces."],"female_lines":["Pas convaincu, les délais souffriront.","Peut-être dans certains secteurs seulement."]},{"point":2,"male_lines":["Le bien-être compte aussi.","Les clients exigent disponibilité."],"female_lines":["Le profit reste essentiel.","On peut organiser des permanences."]},{"point":3,"male_lines":["Testons six mois.","Quels indicateurs ?"],"female_lines":["Risqué.","Productivité et satisfaction."]},{"point":4,"male_lines":["Je parie que ça marchera.","On en reparle dans six mois."],"female_lines":["Moi je doute.","Marché conclu."]}]},{"id":30,"section":"F","theme":"Immigration debate","question":"Quelle est la position de la femme sur l'immigration ?","options":[{"id":"A","text":"Fermer complètement les frontières","image_prompt":""},{"id":"B","text":"Augmenter les quotas actuels","image_prompt":""},{"id":"C","text":"Sélectionner selon les compétences","image_prompt":""},{"id":"D","text":"Faciliter la réunification familiale","image_prompt":""}],"correct":2,"transcript_fr":"Nous devons sélectionner les immigrants selon leurs compétences. C'est inhumain, les réfugiés comptent aussi. Je parle de l'immigration économique, pas humanitaire. Même là, la famille doit primer.","transcript_en":"We must select immigrants according to their skills. It's inhumane, refugees count too. I'm talking about economic immigration, not humanitarian. Even there, family must come first.","points":[{"point":1,"male_lines":["Nous devons sélectionner les immigrants selon leurs compétences.","Je parle de l'immigration économique, pas humanitaire."],"female_lines":["C'est inhumain, les réfugiés comptent aussi.","Même là, la famille doit primer."]},{"point":2,"male_lines":["Le marché du travail a besoin de main-d'œuvre.","On peut combiner les deux."],"female_lines":["Les valeurs humanistes d'abord.","Impossible à gérer équitablement."]},{"point":3,"male_lines":["Le Canada a besoin de médecins.","Et d'ouvriers aussi."],"female_lines":["Et d'enseignants.","D'accord sur ce point."]},{"point":4,"male_lines":["Voyez, on peut s'entendre.","Progressons étape par étape."],"female_lines":["Peut-être.","Surveillons les résultats."]}]},{"id":31,"section":"G","theme":"Scientific discovery","question":"Quelle découverte scientifique est décrite ?","options":[{"id":"A","text":"Une nouvelle espèce marine","image_prompt":""},{"id":"B","text":"Un médicament contre Alzheimer","image_prompt":""},{"id":"C","text":"Une source d'énergie renouvelable","image_prompt":""},{"id":"D","text":"Une planète habitable proche","image_prompt":""}],"correct":0,"transcript_fr":"Chers auditeurs, aujourd'hui nous accueillons le biologiste marin Dr. Bernard. Merci de me recevoir. Vous avez fait une découverte extraordinaire dans les profondeurs. Oui, nous avons identifié une nouvelle espèce de pieuvre géante dans la fosse des Mariannes. Elle mesure plus de cinq mètres. Comment l'avez-vous trouvée ? Notre sous-marin a capté des signaux sonores inhabituels à six mille mètres de profondeur. Qu'est-ce qui rend cette espèce unique ? Elle possède des photophores capables de produire une lumière ultra-violette invisible pour nous. Quelles sont les implications de cette découverte ? Cela remet en question nos théories sur la vie dans l'obscurité totale. Pensez-vous qu'il existe d'autres espèces similaires ? Absolument, nous croyons qu'une vingtaine d'espèces restent à découvrir dans ces abysses. Quel est le prochain projet de votre équipe ? Nous préparons une expédition dans l'océan Arctique l'année prochaine. Merci pour ces révélations fascinantes. C'est un honneur de partager cette science avec vous.","transcript_en":"Dear listeners, today we welcome marine biologist Dr. Bernard. Thank you for having me. You have made an extraordinary discovery in the depths. Yes, we have identified a new species of giant octopus in the Mariana Trench. It measures over five meters. How did you find it? Our submarine captured unusual sound signals at six thousand meters depth. What makes this species unique? It has photophores capable of producing ultraviolet light invisible to us. What are the implications of this discovery? This challenges our theories about life in total darkness. Do you think there are other similar species? Absolutely, we believe about twenty species remain to be discovered in these abysses. What is your team's next project? We are preparing an expedition to the Arctic Ocean next year. Thank you for these fascinating revelations. It is an honor to share this science with you.","points":[{"point":1,"male_lines":["Chers auditeurs, aujourd'hui nous accueillons le biologiste marin Dr. Bernard.","Vous avez fait une découverte extraordinaire dans les profondeurs."],"female_lines":["Merci de me recevoir.","Oui, nous avons identifié une nouvelle espèce de pieuvre géante dans la fosse des Mariannes."]},{"point":2,"male_lines":["Elle mesure plus de cinq mètres.","Comment l'avez-vous trouvée ?"],"female_lines":["C'est exact, un record.","Notre sous-marin a capté des signaux sonores inhabituels à six mille mètres de profondeur."]},{"point":3,"male_lines":["Qu'est-ce qui rend cette espèce unique ?","Quelles sont les implications de cette découverte ?"],"female_lines":["Elle possède des photophores capables de produire une lumière ultra-violette invisible pour nous.","Cela remet en question nos théories sur la vie dans l'obscurité totale."]},{"point":4,"male_lines":["Pensez-vous qu'il existe d'autres espèces similaires ?","Quel est le prochain projet de votre équipe ?"],"female_lines":["Absolument, nous croyons qu'une vingtaine d'espèces restent à découvrir dans ces abysses.","Nous préparons une expédition dans l'océan Arctique l'année prochaine."]},{"point":5,"male_lines":["Merci pour ces révélations fascinantes.","Le public attend avec impatience vos résultats."],"female_lines":["C'est un honneur de partager cette science avec vous.","Nous publierons dans Nature le mois prochain."]},{"point":6,"male_lines":["Une dernière question ?","Comment financez-vous ces recherches ?"],"female_lines":["Oui ?","Par des subventions gouvernementales et des fonds privés."]},{"point":7,"male_lines":["Le gouvernement canadien soutient bien la science.","Les jeunes doivent s'intéresser à ces métiers."],"female_lines":["Heureusement oui.","Nous recrutons d'ailleurs des volontaires."]},{"point":8,"male_lines":["Où postuler ?","Existe-t-il des risques ?"],"female_lines":["Sur notre site web.","Les plongées sont toujours risquées mais passionnantes."]},{"point":9,"male_lines":["Votre courage est admirable.","Merci encore."],"female_lines":["C'est notre passion.","Je vous remercie."]},{"point":10,"male_lines":["Au revoir et bonne continuation.","À bientôt."],"female_lines":["Au revoir.","À la prochaine."]}]},{"id":32,"section":"G","theme":"Historical analysis","question":"Quel événement historique est analysé ?","options":[{"id":"A","text":"La Révolution tranquille","image_prompt":""},{"id":"B","text":"La Conquête de 1760","image_prompt":""},{"id":"C","text":"Les Patriotes de 1837","image_prompt":""},{"id":"D","text":"La Crise d'octobre","image_prompt":""}],"correct":0,"transcript_fr":"Bonjour professeur, bienvenue sur notre émission. Merci, c'est un plaisir. Vous êtes spécialiste de la Révolution tranquille. Exactement, cette période cruciale des années soixante. Quels étaient les facteurs déclenchants ? La population québécoise voulait moderniser ses institutions et sortir de l'influence religieuse. Comment Duplessis a-t-il influencé ce mouvement ? Son régime autoritaire a créé un désir de changement irrépressible chez les jeunes. Quel rôle a joué Jean Lesage ? Il a incarné l'espoir avec sa célèbre phrase 'Il faut que ça change'. Quels secteurs ont été transformés ? L'éducation, la santé et les nationalisations d'Hydro-Québec ont marqué cette ère. Pourquoi 'tranquille' alors ? Car contrairement aux révolutions violentes, celle-ci s'est faite par les urnes et la loi. Quel héritage reste-t-il aujourd'hui ? Un Québec laïc, moderne et maître de son destin économique. Certains regrettent cette époque ? Oui, certains y voient une perte de valeurs traditionnelles. Comment répondez-vous à ces critiques ? Le progrès social demande des sacrifices, mais les bénéfices sont immenses. Merci pour cette analyse éclairante. C'était un honneur de partager ces connaissances.","transcript_en":"Hello professor, welcome to our show. Thank you, it's a pleasure. You are a specialist of the Quiet Revolution. Exactly, this crucial period of the sixties. What were the triggering factors? The Quebec population wanted to modernize its institutions and break away from religious influence. How did Duplessis influence this movement? His authoritarian regime created an irrepressible desire for change among young people. What role did Jean Lesage play? He embodied hope with his famous phrase 'Things must change'. Which sectors were transformed? Education, health and the nationalizations of Hydro-Quebec marked this era. Why 'quiet' then? Because unlike violent revolutions, this one happened through ballots and law. What legacy remains today? A secular, modern Quebec master of its economic destiny. Some regret this period? Yes, some see it as a loss of traditional values. How do you respond to these criticisms? Social progress requires sacrifices, but the benefits are immense. Thank you for this enlightening analysis. It was an honor to share this knowledge.","points":[{"point":1,"male_lines":["Bonjour professeur, bienvenue sur notre émission.","Vous êtes spécialiste de la Révolution tranquille."],"female_lines":["Merci, c'est un plaisir.","Exactement, cette période cruciale des années soixante."]},{"point":2,"male_lines":["Quels étaient les facteurs déclenchants ?","Comment Duplessis a-t-il influencé ce mouvement ?"],"female_lines":["La population québécoise voulait moderniser ses institutions et sortir de l'influence religieuse.","Son régime autoritaire a créé un désir de changement irrépressible chez les jeunes."]},{"point":3,"male_lines":["Quel rôle a joué Jean Lesage ?","Quels secteurs ont été transformés ?"],"female_lines":["Il a incarné l'espoir avec sa célèbre phrase 'Il faut que ça change'.","L'éducation, la santé et les nationalisations d'Hydro-Québec ont marqué cette ère."]},{"point":4,"male_lines":["Pourquoi 'tranquille' alors ?","Quel héritage reste-t-il aujourd'hui ?"],"female_lines":["Car contrairement aux révolutions violentes, celle-ci s'est faite par les urnes et la loi.","Un Québec laïc, moderne et maître de son destin économique."]},{"point":5,"male_lines":["Certains regrettent cette époque ?","Comment répondez-vous à ces critiques ?"],"female_lines":["Oui, certains y voient une perte de valeurs traditionnelles.","Le progrès social demande des sacrifices, mais les bénéfices sont immenses."]},{"point":6,"male_lines":["Merci pour cette analyse éclairante.","Votre livre est-il disponible ?"],"female_lines":["C'était un honneur de partager ces connaissances.","Oui, dans toutes les librairies depuis hier."]},{"point":7,"male_lines":["Quel est votre prochain projet de recherche ?","Les archives sont-elles accessibles ?"],"female_lines":["J'étudie maintenant les femmes de cette époque.","Certaines restent confidentielles."]},{"point":8,"male_lines":["Une figure féminine à retenir ?","Votre message aux jeunes ?"],"female_lines":["Marie-Claire Kirkland, première femme ministre.","Étudiez votre histoire pour mieux construire l'avenir."]},{"point":9,"male_lines":["Excellente conclusion.","Merci infiniment."],"female_lines":["Merci à vous.","C'était enrichissant."]},{"point":10,"male_lines":["Au revoir professeur.","Bonne journée."],"female_lines":["Au revoir.","À bientôt."]}]},{"id":33,"section":"G","theme":"Economic crisis","question":"Quelle crise économique est discutée ?","options":[{"id":"A","text":"La crise de 1929","image_prompt":""},{"id":"B","text":"La crise des subprimes de 2008","image_prompt":""},{"id":"C","text":"La crise pétrolière des années 70","image_prompt":""},{"id":"D","text":"La crise de la dette grecque","image_prompt":""}],"correct":1,"transcript_fr":"Bonjour Madame l'économiste, parlons de 2008. Oui, cette année noire des marchés financiers. Quelle était la cause principale ? Les prêts hypothécaires à risque accordés à des emprunteurs non solvables. Comment les banques ont-elles réagi ? Elles ont paqueté ces dettes toxiques en produits financiers complexes. Qui a été le plus touché ? Les ménages américains ont perdu leurs maisons, puis la contagion s'est mondialisée. Le Canada a résisté ? Relativement, grâce à une réglementation bancaire plus stricte. Quelles leçons avons-nous tirées ? La nécessité de contrôler les produits dérivés et de séparer banques de détail et d'investissement. Ces réformes ont-elles été appliquées ? Partiellement, le lobbys financier reste puissant. Voyez-vous des signes avant-coureurs aujourd'hui ? La bulle immobilière canadienne m'inquiète particulièrement. Que recommandez-vous aux épargnants ? Diversifier leurs placements et éviter l'endettement excessif. Merci pour ces avertissements. Il faut rester vigilant face aux excès du capitalisme.","transcript_en":"Hello Madam economist, let's talk about 2008. Yes, that black year for financial markets. What was the main cause? Risky mortgages granted to insolvent borrowers. How did the banks react? They packaged these toxic debts into complex financial products. Who was most affected? American households lost their homes, then the contagion went global. Did Canada resist? Relatively, thanks to stricter banking regulations. What lessons have we learned? The necessity to control derivatives and separate retail and investment banks. Have these reforms been applied? Partially, financial lobbying remains powerful. Do you see warning signs today? The Canadian real estate bubble worries me particularly. What do you recommend to savers? Diversify their investments and avoid excessive debt. Thank you for these warnings. We must remain vigilant against the excesses of capitalism.","points":[{"point":1,"male_lines":["Bonjour Madame l'économiste, parlons de 2008.","Quelle était la cause principale ?"],"female_lines":["Oui, cette année noire des marchés financiers.","Les prêts hypothécaires à risque accordés à des emprunteurs non solvables."]},{"point":2,"male_lines":["Comment les banques ont-elles réagi ?","Qui a été le plus touché ?"],"female_lines":["Elles ont paqueté ces dettes toxiques en produits financiers complexes.","Les ménages américains ont perdu leurs maisons, puis la contagion s'est mondialisée."]},{"point":3,"male_lines":["Le Canada a résisté ?","Quelles leçons avons-nous tirées ?"],"female_lines":["Relativement, grâce à une réglementation bancaire plus stricte.","La nécessité de contrôler les produits dérivés et de séparer banques de détail et d'investissement."]},{"point":4,"male_lines":["Ces réformes ont-elles été appliquées ?","Voyez-vous des signes avant-coureurs aujourd'hui ?"],"female_lines":["Partiellement, le lobbys financier reste puissant.","La bulle immobilière canadienne m'inquiète particulièrement."]},{"point":5,"male_lines":["Que recommandez-vous aux épargnants ?","Merci pour ces avertissements."],"female_lines":["Diversifier leurs placements et éviter l'endettement excessif.","Il faut rester vigilant face aux excès du capitalisme."]},{"point":6,"male_lines":["Les jeunes générations sont-elles préparées ?","L'éducation financière manque ?"],"female_lines":["Malheureusement non.","Absolument, il faut l'introduire à l'école."]},{"point":7,"male_lines":["Quel est votre livre de chevet ?","Keynes encore d'actualité ?"],"female_lines":["L'économie de Adam Smith.","Toujours pertinent dans la crise."]},{"point":8,"male_lines":["Votre prochaine conférence ?","Où peut-on vous voir ?"],"female_lines":["À l'Université de Montréal.","Le 15 mars prochain."]},{"point":9,"male_lines":["Nous y serons.","Merci pour tout."],"female_lines":["Excellent.","Je vous en prie."]},{"point":10,"male_lines":["Au revoir.","Bonne continuation."],"female_lines":["Au revoir.","À bientôt."]}]},{"id":34,"section":"G","theme":"Literary analysis","question":"Quel auteur québécois est analysé ?","options":[{"id":"A","text":"Gabrielle Roy","image_prompt":""},{"id":"B","text":"Yves Beauchemin","image_prompt":""},{"id":"C","text":"Michel Tremblay","image_prompt":""},{"id":"D","text":"Anne Hébert","image_prompt":""}],"correct":2,"transcript_fr":"Bonjour, bienvenue dans notre club de lecture. Merci, c'est un honneur. Vous allez nous parler de Michel Tremblay. Exactement, ce géant de la littérature québécoise. Quelle œuvre allez-vous analyser ? 'Les Belles-Sœurs', son chef-d'œuvre inaugural. Pourquoi cette pièce est-elle si importante ? Elle a révolutionné le théâtre en utilisant le joual, la langue du peuple. Racontez-nous l'intrigue. Quinze femmes collent des timbres-primes dans un salon montréalais, c'est toute une société qui se révèle. Quels thèmes principaux ? La pauvreté, la jalousie féminine et la quête d'évasion par la consommation. Comment les personnages évoluent-ils ? Germaine Lauzon passe de l'euphorie à la désillusion tragique. Quel impact sur la culture québécoise ? Il a donné une voix légitime aux classes populaires. Ses autres œuvres majeures ? 'Bonjour, la, bonjour' et la saga des 'Chroniques du Plateau-Mont-Royal'. Pourquoi Tremblay reste-t-il actuel ? Parce qu'il parle de l'humain universel avec une authenticité brute. Merci pour cette passionnante analyse. C'était un plaisir de partager cette admiration.","transcript_en":"Hello, welcome to our book club. Thank you, it's an honor. You will talk to us about Michel Tremblay. Exactly, this giant of Quebec literature. Which work will you analyze? 'Les Belles-Sœurs', his inaugural masterpiece. Why is this play so important? It revolutionized theater by using joual, the language of the people. Tell us the plot. Fifteen women paste trading stamps in a Montreal living room, it's an entire society that reveals itself. What are the main themes? Poverty, female jealousy and the quest for escape through consumption. How do the characters evolve? Germaine Lauzon goes from euphoria to tragic disillusionment. What impact on Quebec culture? He gave a legitimate voice to the working classes. His other major works? 'Bonjour, la, bonjour' and the 'Chronicles of Plateau-Mont-Royal' saga. Why does Tremblay remain relevant? Because he speaks of universal humanity with raw authenticity. Thank you for this fascinating analysis. It was a pleasure to share this admiration.","points":[{"point":1,"male_lines":["Bonjour, bienvenue dans notre club de lecture.","Vous allez nous parler de Michel Tremblay."],"female_lines":["Merci, c'est un honneur.","Exactement, ce géant de la littérature québécoise."]},{"point":2,"male_lines":["Quelle œuvre allez-vous analyser ?","Pourquoi cette pièce est-elle si importante ?"],"female_lines":["'Les Belles-Sœurs', son chef-d'œuvre inaugural.","Elle a révolutionné le théâtre en utilisant le joual, la langue du peuple."]},{"point":3,"male_lines":["Racontez-nous l'intrigue.","Quels thèmes principaux ?"],"female_lines":["Quinze femmes collent des timbres-primes dans un salon montréalais, c'est toute une société qui se révèle.","La pauvreté, la jalousie féminine et la quête d'évasion par la consommation."]},{"point":4,"male_lines":["Comment les personnages évoluent-ils ?","Quel impact sur la culture québécoise ?"],"female_lines":["Germaine Lauzon passe de l'euphorie à la désillusion tragique.","Il a donné une voix légitime aux classes populaires."]},{"point":5,"male_lines":["Ses autres œuvres majeures ?","Pourquoi Tremblay reste-t-il actuel ?"],"female_lines":["'Bonjour, la, bonjour' et la saga des 'Chroniques du Plateau-Mont-Royal'.","Parce qu'il parle de l'humain universel avec une authenticité brute."]},{"point":6,"male_lines":["Merci pour cette passionnante analyse.","Avez-vous rencontré l'auteur ?"],"female_lines":["C'était un plaisir de partager cette admiration.","Oui, une fois à la Place des Arts."]},{"point":7,"male_lines":["Comment était-il ?","Accessibles avec ses fans ?"],"female_lines":["Très humble malgré son succès.","Extrêmement, il signait des autographes pendant des heures."]},{"point":8,"male_lines":["Quel conseil aux jeunes écrivains ?","Écrire en joual aujourd'hui ?"],"female_lines":["Écrire ce qu'on vit sincèrement.","Pourquoi pas, l'authenticité prime."]},{"point":9,"male_lines":["Prochain auteur au programme ?","Nous avons hâte."],"female_lines":["Marie-Claire Blais.","Excellente idée."]},{"point":10,"male_lines":["Merci encore.","Au revoir."],"female_lines":["Je vous en prie.","Au revoir."]}]},{"id":35,"section":"G","theme":"Medical ethics","question":"Quel dilemme éthique est discuté ?","options":[{"id":"A","text":"L'euthanasie","image_prompt":""},{"id":"B","text":"Le clonage humain","image_prompt":""},{"id":"C","text":"La manipulation génétique","image_prompt":""},{"id":"D","text":"L'accès aux soins palliatifs","image_prompt":""}],"correct":0,"transcript_fr":"Docteur, l'aide médicale à mourir divise la société. Oui, c'est une question profondément complexe. Quels sont les arguments des partisans ? Le droit à la dignité et la fin des souffrances insoutenables. Et les opposants ? Ils craignent l'effet de glissement vers des pratiques eugéniques. Comment encadre-t-on cela au Canada ? Deux médecins indépendants doivent confirmer l'irréversibilité de la situation. Quels critères doivent être remplis ? Maladie grave, déclin irrémédiable et souffrance physique ou psychologique. La clause de conscience existe-t-elle ? Oui, aucun médecin n'est obligé de pratiquer l'AMM. Comment accompagner les familles ? Avec une équipe interdisciplinaire de soins palliatifs. Les demandes augmentent-elles ? Oui, de 30% chaque année depuis la légalisation. Quel est votre position personnelle ? Je respecte le choix des patients tout en privilégiant les soins palliatifs. Merci pour cette nuance essentielle. C'est notre devoir d'humanité.","transcript_en":"Doctor, medical assistance in dying divides society. Yes, it is a deeply complex issue. What are the arguments of supporters? The right to dignity and the end of unbearable suffering. And opponents? They fear the slippery slope toward eugenic practices. How is this regulated in Canada? Two independent doctors must confirm the irreversibility of the situation. What criteria must be met? Serious illness, irreversible decline and physical or psychological suffering. Does the conscience clause exist? Yes, no doctor is forced to practice MAID. How are families supported? With an interdisciplinary palliative care team. Are requests increasing? Yes, 30% each year since legalization. What is your personal position? I respect patients' choice while prioritizing palliative care. Thank you for this essential nuance. It is our duty of humanity.","points":[{"point":1,"male_lines":["Docteur, l'aide médicale à mourir divise la société.","Quels sont les arguments des partisans ?"],"female_lines":["Oui, c'est une question profondément complexe.","Le droit à la dignité et la fin des souffrances insoutenables."]},{"point":2,"male_lines":["Et les opposants ?","Comment encadre-t-on cela au Canada ?"],"female_lines":["Ils craignent l'effet de glissement vers des pratiques eugéniques.","Deux médecins indépendants doivent confirmer l'irréversibilité de la situation."]},{"point":3,"male_lines":["Quels critères doivent être remplis ?","La clause de conscience existe-t-elle ?"],"female_lines":["Maladie grave, déclin irrémédiable et souffrance physique ou psychologique.","Oui, aucun médecin n'est obligé de pratiquer l'AMM."]},{"point":4,"male_lines":["Comment accompagner les familles ?","Les demandes augmentent-elles ?"],"female_lines":["Avec une équipe interdisciplinaire de soins palliatifs.","Oui, de 30% chaque année depuis la légalisation."]},{"point":5,"male_lines":["Quel est votre position personnelle ?","Merci pour cette nuance essentielle."],"female_lines":["Je respecte le choix des patients tout en privilégiant les soins palliatifs.","C'est notre devoir d'humanité."]},{"point":6,"male_lines":["Les psychiatres sont-ils impliqués ?","Pour les troubles mentaux ?"],"female_lines":["Oui, désormais.","Un débat récent et sensible."]},{"point":7,"male_lines":["Quelle formation pour les médecins ?","Elle est obligatoire ?"],"female_lines":["Douze heures d'enseignement éthique.","Recommandée mais pas obligatoire."]},{"point":8,"male_lines":["Les infirmiers participent ?","Dans quelle mesure ?"],"female_lines":["À l'administration des médicaments.","Sous supervision médicale stricte."]},{"point":9,"male_lines":["L'avenir de cette loi ?","Des révisions prévues ?"],"female_lines":["Des ajustements constants nécessaires.","Oui, l'élargissement aux mineurs débattu."]},{"point":10,"male_lines":["Merci pour cette expertise.","Au revoir docteur."],"female_lines":["C'est ma mission.","Au revoir."]}]},{"id":36,"section":"H","theme":"Philosophical debate","question":"Quelle question philosophique est abordée ?","options":[{"id":"A","text":"Le libre arbitre existe-t-il ?","image_prompt":""},{"id":"B","text":"Qu'est-ce que la justice ?","image_prompt":""},{"id":"C","text":"Le sens de la vie","image_prompt":""},{"id":"D","text":"La nature de la conscience","image_prompt":""}],"correct":0,"transcript_fr":"Professeur, le libre arbitre est-il une illusion ? Excellente question qui divise les philosophes depuis des siècles. Qu'en dit la science moderne ? Les neurosciences suggèrent que nos décisions sont prises avant notre conscience. Donc pas de liberté ? Pas si simple, la conscience peut inhiber certaines actions. C'est quoi le déterminisme ? L'idée que tout événement est la conséquence nécessaire de causes antérieures. Et le compatibilisme ? Cette thèse défend que déterminisme et liberté ne s'opposent pas. Kant disait quoi à ce sujet ? Il distinguait le phénomène observable et le noumène, domaine de la liberté. L'existentialisme sartrien alors ? L'existence précède l'essence, nous sommes condamnés à être libres. C'est une liberté angoissante ? Oui, car nous portons l'entière responsabilité de nos choix. Comment concilier tout cela ? Peut-être en acceptant que notre liberté s'exerce dans des contraintes données. Merci pour cette clarification. La philosophie reste essentielle pour questionner nos certitudes.","transcript_en":"Professor, is free will an illusion? Excellent question that has divided philosophers for centuries. What does modern science say? Neuroscience suggests that our decisions are made before our consciousness. So no freedom? Not so simple, consciousness can inhibit certain actions. What is determinism? The idea that every event is the necessary consequence of previous causes. And compatibilism? This thesis argues that determinism and freedom are not opposed. What did Kant say about this? He distinguished the observable phenomenon and the noumenon, domain of freedom. What about Sartrean existentialism? Existence precedes essence, we are condemned to be free. Is it an anxious freedom? Yes, because we bear full responsibility for our choices. How to reconcile all this? Perhaps by accepting that our freedom operates within given constraints. Thank you for this clarification. Philosophy remains essential for questioning our certainties.","points":[{"point":1,"male_lines":["Professeur, le libre arbitre est-il une illusion ?","Qu'en dit la science moderne ?"],"female_lines":["Excellente question qui divise les philosophes depuis des siècles.","Les neurosciences suggèrent que nos décisions sont prises avant notre conscience."]},{"point":2,"male_lines":["Donc pas de liberté ?","C'est quoi le déterminisme ?"],"female_lines":["Pas si simple, la conscience peut inhiber certaines actions.","L'idée que tout événement est la conséquence nécessaire de causes antérieures."]},{"point":3,"male_lines":["Et le compatibilisme ?","Kant disait quoi à ce sujet ?"],"female_lines":["Cette thèse défend que déterminisme et liberté ne s'opposent pas.","Il distinguait le phénomène observable et le noumène, domaine de la liberté."]},{"point":4,"male_lines":["L'existentialisme sartrien alors ?","C'est une liberté angoissante ?"],"female_lines":["L'existence précède l'essence, nous sommes condamnés à être libres.","Oui, car nous portons l'entière responsabilité de nos choix."]},{"point":5,"male_lines":["Comment concilier tout cela ?","Merci pour cette clarification."],"female_lines":["Peut-être en acceptant que notre liberté s'exerce dans des contraintes données.","La philosophie reste essentielle pour questionner nos certitudes."]},{"point":6,"male_lines":["Les stoïciens disaient ?","Accepter ce qu'on ne contrôle pas ?"],"female_lines":["Exactement.","La dichotomie du contrôle, fondamentale."]},{"point":7,"male_lines":["Et Spinoza ?","Dieu ou Nature ?"],"female_lines":["Substance unique.","Nous en sommes des modes, pas de liberté absolue."]},{"point":8,"male_lines":["Votre position finale ?","Vous croyez au libre arbitre ?"],"female_lines":["Pragmatique.","Je vis comme si j'étais libre, cela suffit."]},{"point":9,"male_lines":["Une lecture à recommander ?","Pour approfondir ?"],"female_lines":["'L'Être et le Néant' de Sartre.","Difficile mais récompensant."]},{"point":10,"male_lines":["Nous nous y mettrons.","Merci professeur."],"female_lines":["Bonne lecture.","À votre service."]}]},{"id":37,"section":"H","theme":"Artificial intelligence","question":"Quelle préoccupation concernant l'IA est soulevée ?","options":[{"id":"A","text":"La perte d'emplois","image_prompt":""},{"id":"B","text":"La singularité technologique","image_prompt":""},{"id":"C","text":"Les biais algorithmiques","image_prompt":""},{"id":"D","text":"La vie privée","image_prompt":""}],"correct":1,"transcript_fr":"Docteur, la singularité technologique est-elle proche ? Certains experts prédisent 2045, d'autres disent que c'est un mythe. Définissez ce concept. Le moment où l'IA dépassera l'intelligence humaine et s'améliorera elle-même. C'est dangereux ? Potentiellement oui, si les objectifs de l'IA ne sont pas alignés avec les nôtres. Comment aligner ces objectifs ? C'est le problème de l'alignement, extrêmement complexe. Quels scénarios catastrophe imaginez-vous ? Un système optimisant une mauvaise métrique, comme la production de trombones à tout prix. Et les scénarios positifs ? Résolution des maladies, inégalités et changement climatique. Pourquoi tant d'urgence maintenant ? Parce que les progrès s'accélèrent exponentiellement. Les gouvernements régulent-ils ? Trop lentement, la technologie avance plus vite que les lois. Que peut faire le citoyen lambda ? S'informer et exiger une transparence des entreprises tech. Merci pour cet avertissement. L'avenir dépend de nos choix collectifs aujourd'hui.","transcript_en":"Doctor, is the technological singularity near? Some experts predict 2045, others say it's a myth. Define this concept. The moment when AI surpasses human intelligence and improves itself. Is it dangerous? Potentially yes, if AI goals are not aligned with ours. How to align these goals? This is the alignment problem, extremely complex. What catastrophic scenarios do you imagine? A system optimizing a bad metric, like producing paperclips at all costs. And positive scenarios? Solving diseases, inequalities and climate change. Why so much urgency now? Because progress is accelerating exponentially. Are governments regulating? Too slowly, technology advances faster than laws. What can the average citizen do? Get informed and demand transparency from tech companies. Thank you for this warning. The future depends on our collective choices today.","points":[{"point":1,"male_lines":["Docteur, la singularité technologique est-elle proche ?","Définissez ce concept."],"female_lines":["Certains experts prédisent 2045, d'autres disent que c'est un mythe.","Le moment où l'IA dépassera l'intelligence humaine et s'améliorera elle-même."]},{"point":2,"male_lines":["C'est dangereux ?","Comment aligner ces objectifs ?"],"female_lines":["Potentiellement oui, si les objectifs de l'IA ne sont pas alignés avec les nôtres.","C'est le problème de l'alignement, extrêmement complexe."]},{"point":3,"male_lines":["Quels scénarios catastrophe imaginez-vous ?","Et les scénarios positifs ?"],"female_lines":["Un système optimisant une mauvaise métrique, comme la production de trombones à tout prix.","Résolution des maladies, inégalités et changement climatique."]},{"point":4,"male_lines":["Pourquoi tant d'urgence maintenant ?","Les gouvernements régulent-ils ?"],"female_lines":["Parce que les progrès s'accélèrent exponentiellement.","Trop lentement, la technologie avance plus vite que les lois."]},{"point":5,"male_lines":["Que peut faire le citoyen lambda ?","Merci pour cet avertissement."],"female_lines":["S'informer et exiger une transparence des entreprises tech.","L'avenir dépend de nos choix collectifs aujourd'hui."]},{"point":6,"male_lines":["L'IA créative inquiète ?","Les artistes remplacés ?"],"female_lines":["Beaucoup.","L'originalité humaine reste irremplaçable selon moi."]},{"point":7,"male_lines":["La conscience artificielle possible ?","Un jour ?"],"female_lines":["Philosophiquement ouvert.","Peut-être, mais pas avant longtemps."]},{"point":8,"male_lines":["Votre confiance en l'humanité ?","Nous survivrons ?"],"female_lines":["Prudente.","Si nous agissons intelligemment maintenant."]},{"point":9,"male_lines":["Un livre sur le sujet ?","Pour nous éduquer ?"],"female_lines":["'Superintelligence' de Bostrom.","Essentiel mais inquiétant."]},{"point":10,"male_lines":["Nous le lirons.","Merci docteur."],"female_lines":["Faites-le vite.","De rien."]}]},{"id":38,"section":"H","theme":"Space exploration","question":"Quel défi de l'exploration spatiale est discuté ?","options":[{"id":"A","text":"Le voyage vers Mars","image_prompt":""},{"id":"B","text":"La colonisation de la Lune","image_prompt":""},{"id":"C","text":"Les trous noirs","image_prompt":""},{"id":"D","text":"La vie extraterrestre","image_prompt":""}],"correct":0,"transcript_fr":"Ingénieur, le voyage habité vers Mars est-il réalisable ? Techniquement oui, mais extrêmement difficile. Quels sont les obstacles majeurs ? La radiation cosmique, l'isolement psychologique et la durée du voyage. Combien de temps dure le trajet ? Minimum six mois avec les technologies actuelles. Comment protéger les astronautes ? Blindage magnétique et médicaments radioprotecteurs en développement. Et la gravité zéro ? Exercices intensifs et possible rotation du vaisseau pour simuler la gravité. Qu'en est-il de la nourriture ? Agriculture hydroponique et rations lyophilisées recyclées. Le retour est-il possible ? Oui, mais beaucoup préconisent des missions sans retour initiales. Pourquoi Mars précisément ? C'est la planète la plus habitable du système solaire après la Terre. Quel calendrier envisagez-vous ? SpaceX parle de 2029, la NASA de 2035 au plus tôt. Le coût est énorme ? Des centaines de milliards, mais l'Humanité doit devenir multiplanétaire. Merci pour cette vision d'avenir. C'est notre destinée d'explorer.","transcript_en":"Engineer, is manned travel to Mars feasible? Technically yes, but extremely difficult. What are the major obstacles? Cosmic radiation, psychological isolation and journey duration. How long does the trip take? Minimum six months with current technologies. How to protect astronauts? Magnetic shielding and radioprotective drugs in development. What about zero gravity? Intensive exercises and possible spacecraft rotation to simulate gravity. What about food? Hydroponic agriculture and recycled freeze-dried rations. Is return possible? Yes, but many advocate initial one-way missions. Why Mars specifically? It is the most habitable planet in the solar system after Earth. What timeline do you envision? SpaceX talks about 2029, NASA says 2035 at the earliest. The cost is huge? Hundreds of billions, but Humanity must become multiplanetary. Thank you for this vision of the future. It is our destiny to explore.","points":[{"point":1,"male_lines":["Ingénieur, le voyage habité vers Mars est-il réalisable ?","Quels sont les obstacles majeurs ?"],"female_lines":["Techniquement oui, mais extrêmement difficile.","La radiation cosmique, l'isolement psychologique et la durée du voyage."]},{"point":2,"male_lines":["Combien de temps dure le trajet ?","Comment protéger les astronautes ?"],"female_lines":["Minimum six mois avec les technologies actuelles.","Blindage magnétique et médicaments radioprotecteurs en développement."]},{"point":3,"male_lines":["Et la gravité zéro ?","Qu'en est-il de la nourriture ?"],"female_lines":["Exercices intensifs et possible rotation du vaisseau pour simuler la gravité.","Agriculture hydroponique et rations lyophilisées recyclées."]},{"point":4,"male_lines":["Le retour est-il possible ?","Pourquoi Mars précisément ?"],"female_lines":["Oui, mais beaucoup préconisent des missions sans retour initiales.","C'est la planète la plus habitable du système solaire après la Terre."]},{"point":5,"male_lines":["Quel calendrier envisagez-vous ?","Le coût est énorme ?"],"female_lines":["SpaceX parle de 2029, la NASA de 2035 au plus tôt.","Des centaines de milliards, mais l'Humanité doit devenir multiplanétaire."]},{"point":6,"male_lines":["Les volontaires sont nombreux ?","Des milliers ?"],"female_lines":["Des centaines de milliers se sont portés candidats.","L'aventure les attire malgré les risques."]},{"point":7,"male_lines":["La sélection est drastique ?","Quels critères ?"],"female_lines":["Extrêmement.","Santé parfaite, psychologie solide, compétences techniques."]},{"point":8,"male_lines":["L'entraînement dure combien ?","Des années ?"],"female_lines":["Minimum deux ans.","Simulation complète de la mission."]},{"point":9,"male_lines":["Vous y iriez vous-même ?","Si on vous proposait ?"],"female_lines":["Honnêtement ?","Oui, sans hésiter pour l'Humanité."]},{"point":10,"male_lines":["Votre courage est admirable.","Merci ingénieur."],"female_lines":["C'est la passion de l'exploration.","De rien."]}]},{"id":39,"section":"H","theme":"Consciousness studies","question":"Quelle théorie de la conscience est présentée ?","options":[{"id":"A","text":"L'intégration informationnelle","image_prompt":""},{"id":"B","text":"Le matérialisme éliminatif","image_prompt":""},{"id":"C","text":"Le panpsychisme","image_prompt":""},{"id":"D","text":"L'émergentisme","image_prompt":""}],"correct":2,"transcript_fr":"Docteur, le panpsychisme fait débat en philosophie de l'esprit. Oui, cette théorie ancienne remise au goût du jour. Quelle est sa thèse centrale ? Que la conscience est une propriété fondamentale de la matière, comme la masse. Même les électrons seraient conscients ? Dans un sens minimal, oui, une forme d'expérience primitive. C'est du mysticisme ? Non, c'est une théorie scientifique sérieuse défendue par des philosophes analytiques. Comment explique-t-il la conscience complexe ? Par la combinaison de micro-expériences en macro-expérience via l'organisation. Le problème difficile reste entier ? Il le résout en disant que la conscience n'est pas émergente mais omniprésente. Et l'évolution ? La sélection naturelle a favorisé les organisations complexes de conscience. Les critiques disent quoi ? Que c'est une théorie impossible à tester empiriquement. Votre position ? Je trouve cela élégant mais je reste agnostique. Merci pour cette introduction fascinante. La conscience reste le dernier grand mystère.","transcript_en":"Doctor, panpsychism is debated in philosophy of mind. Yes, this ancient theory is making a comeback. What is its central thesis? That consciousness is a fundamental property of matter, like mass. Even electrons would be conscious? In a minimal sense, yes, a form of primitive experience. Is this mysticism? No, it is a serious scientific theory defended by analytical philosophers. How does it explain complex consciousness? Through the combination of micro-experiences into macro-experience via organization. The hard problem remains? It solves it by saying consciousness is not emergent but omnipresent. And evolution? Natural selection favored complex organizations of consciousness. What do critics say? That it is a theory impossible to test empirically. Your position? I find it elegant but remain agnostic. Thank you for this fascinating introduction. Consciousness remains the last great mystery.","points":[{"point":1,"male_lines":["Docteur, le panpsychisme fait débat en philosophie de l'esprit.","Quelle est sa thèse centrale ?"],"female_lines":["Oui, cette théorie ancienne remise au goût du jour.","Que la conscience est une propriété fondamentale de la matière, comme la masse."]},{"point":2,"male_lines":["Même les électrons seraient conscients ?","C'est du mysticisme ?"],"female_lines":["Dans un sens minimal, oui, une forme d'expérience primitive.","Non, c'est une théorie scientifique sérieuse défendue par des philosophes analytiques."]},{"point":3,"male_lines":["Comment explique-t-il la conscience complexe ?","Le problème difficile reste entier ?"],"female_lines":["Par la combinaison de micro-expériences en macro-expérience via l'organisation.","Il le résout en disant que la conscience n'est pas émergente mais omniprésente."]},{"point":4,"male_lines":["Et l'évolution ?","Les critiques disent quoi ?"],"female_lines":["La sélection naturelle a favorisé les organisations complexes de conscience.","Que c'est une théorie impossible à tester empiriquement."]},{"point":5,"male_lines":["Votre position ?","Merci pour cette introduction fascinante."],"female_lines":["Je trouve cela élégant mais je reste agnostique.","La conscience reste le dernier grand mystère."]},{"point":6,"male_lines":["Chalmers défend cette thèse ?","Le célèbre philosophe ?"],"female_lines":["Oui, parmi d'autres.","Il a popularisé le problème difficile."]},{"point":7,"male_lines":["Et Dennett ?","L'adversaire ?"],"female_lines":["Il rejette tout le concept.","Pour lui, la conscience est une illusion."]},{"point":8,"male_lines":["Qui a raison selon vous ?","Le débat continue ?"],"female_lines":["Les deux ont des arguments solides.","Oui, et c'est passionnant."]},{"point":9,"male_lines":["Une expérience pour trancher ?","Un jour peut-être ?"],"female_lines":["Pas encore imaginable.","La science progresse vite pourtant."]},{"point":10,"male_lines":["Merci pour cette érudition.","Au revoir."],"female_lines":["C'est un plaisir.","Au revoir."]}]},{"id":40,"section":"H","theme":"Quantum physics","question":"Quel concept de physique quantique est expliqué ?","options":[{"id":"A","text":"L'intrication quantique","image_prompt":""},{"id":"B","text":"Le chat de Schrödinger","image_prompt":""},{"id":"C","text":"Le principe d'incertitude","image_prompt":""},{"id":"D","text":"La décohérence quantique","image_prompt":""}],"correct":0,"transcript_fr":"Professeur, expliquez-nous l'intrication quantique. C'est un phénomène où deux particules restent connectées instantanément quelle que soit la distance. C'est de la téléportation ? Non, c'est une corrélation non locale, pas de transfert d'information. Einstein n'aimait pas ça ? Il parlait d'effet fantôme à distance, trouvant cela absurde. Mais il avait tort ? Les expériences d'Aspect en 1982 ont confirmé l'intrication. Applications concrètes ? La cryptographie quantique inviolable et l'informatique quantique. Comment ça marche exactement ? Mesurer l'état d'une particule détermine instantanément l'état de l'autre, sans communication. Cela viole la relativité ? Non, car on ne peut pas transmettre d'information plus vite que la lumière. Pourquoi est-ce important philosophiquement ? Cela remet en cause notre conception de la réalité locale et indépendante. L'avenir est quantique ? Absolument, une révolution technologique est en marche. Merci pour ces explications. La physique quantique défie l'intuition mais décrit la réalité.","transcript_en":"Professor, explain quantum entanglement to us. It is a phenomenon where two particles remain connected instantaneously regardless of distance. Is this teleportation? No, it is a non-local correlation, not information transfer. Einstein didn't like this? He spoke of spooky action at a distance, finding it absurd. But he was wrong? Aspect's experiments in 1982 confirmed entanglement. Concrete applications? Unbreakable quantum cryptography and quantum computing. How exactly does it work? Measuring the state of one particle instantly determines the state of the other, without communication. Does this violate relativity? No, because information cannot be transmitted faster than light. Why is this philosophically important? It challenges our conception of local and independent reality. The future is quantum? Absolutely, a technological revolution is underway. Thank you for these explanations. Quantum physics defies intuition but describes reality.","points":[{"point":1,"male_lines":["Professeur, expliquez-nous l'intrication quantique.","C'est de la téléportation ?"],"female_lines":["C'est un phénomène où deux particules restent connectées instantanément quelle que soit la distance.","Non, c'est une corrélation non locale, pas de transfert d'information."]},{"point":2,"male_lines":["Einstein n'aimait pas ça ?","Mais il avait tort ?"],"female_lines":["Il parlait d'effet fantôme à distance, trouvant cela absurde.","Les expériences d'Aspect en 1982 ont confirmé l'intrication."]},{"point":3,"male_lines":["Applications concrètes ?","Comment ça marche exactement ?"],"female_lines":["La cryptographie quantique inviolable et l'informatique quantique.","Mesurer l'état d'une particule détermine instantanément l'état de l'autre, sans communication."]},{"point":4,"male_lines":["Cela viole la relativité ?","Pourquoi est-ce important philosophiquement ?"],"female_lines":["Non, car on ne peut pas transmettre d'information plus vite que la lumière.","Cela remet en cause notre conception de la réalité locale et indépendante."]},{"point":5,"male_lines":["L'avenir est quantique ?","Merci pour ces explications."],"female_lines":["Absolument, une révolution technologique est en marche.","La physique quantique défie l'intuition mais décrit la réalité."]},{"point":6,"male_lines":["Les ordinateurs quantiques fonctionnent ?","IBM et Google avancent ?"],"female_lines":["Encore instables.","Oui, mais l'erreur reste élevée."]},{"point":7,"male_lines":["Quand la suprématie quantique ?","Prévisible ?"],"female_lines":["Déjà revendiquée par Google.","Mais pas encore utilisable concrètement."]},{"point":8,"male_lines":["Les risques sécuritaires ?","La cryptographie classique ?"],"female_lines":["Elle deviendra obsolète.","Il faut déjà préparer la cryptographie post-quantique."]},{"point":9,"male_lines":["Votre domaine de recherche ?","Vous travaillez sur quoi ?"],"female_lines":["Les qubits supraconducteurs.","Très prometteurs mais fragiles."]},{"point":10,"male_lines":["Bonne chance.","Merci professeur."],"female_lines":["Merci.","Au revoir."]}]}]`);export{e as default};
